<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Expense Tracker</title>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: system-ui, sans-serif; background: #f0f2f5; color: #222; min-height: 100vh; }
  .container { max-width: 800px; margin: 0 auto; padding: 24px 16px; }
  h1 { font-size: 1.6rem; margin-bottom: 20px; color: #1a1a2e; }
  h2 { font-size: 1.1rem; margin-bottom: 12px; color: #333; }
  .card { background: #fff; border-radius: 8px; padding: 20px; margin-bottom: 20px; box-shadow: 0 1px 4px rgba(0,0,0,0.08); }
  .form-row { display: flex; gap: 10px; flex-wrap: wrap; margin-bottom: 10px; }
  .form-group { display: flex; flex-direction: column; gap: 4px; flex: 1; min-width: 120px; }
  .form-group label { font-size: 0.8rem; font-weight: 600; color: #555; text-transform: uppercase; letter-spacing: 0.04em; }
  input, select { padding: 8px 10px; border: 1px solid #d1d5db; border-radius: 6px; font-size: 0.95rem; background: #fff; color: #222; width: 100%; }
  input:focus, select:focus { outline: 2px solid #4f7cff; border-color: transparent; }
  #note { width: 100%; }
  #form-error { color: #c0392b; font-size: 0.88rem; min-height: 1.2em; margin-top: 4px; }
  #add-expense { padding: 9px 22px; background: #4f7cff; color: #fff; border: none; border-radius: 6px; font-size: 0.95rem; font-weight: 600; cursor: pointer; margin-top: 6px; }
  #add-expense:hover { background: #3a63e0; }
  .filters { display: flex; gap: 10px; flex-wrap: wrap; align-items: flex-end; }
  .filters .form-group { min-width: 110px; }
  .summary-grid { display: flex; gap: 10px; flex-wrap: wrap; margin-bottom: 16px; }
  .summary-grid .cat-box { background: #f7f8fa; border: 1px solid #e5e7eb; border-radius: 6px; padding: 10px 14px; min-width: 120px; }
  .cat-label { font-size: 0.75rem; font-weight: 600; color: #888; text-transform: uppercase; }
  .cat-total { font-size: 1.1rem; font-weight: 700; color: #1a1a2e; margin-top: 2px; }
  #total-row { font-size: 1rem; font-weight: 700; color: #1a1a2e; margin-bottom: 12px; }
  #total-row span { color: #4f7cff; }
  table { width: 100%; border-collapse: collapse; font-size: 0.92rem; }
  thead th { text-align: left; padding: 8px 10px; border-bottom: 2px solid #e5e7eb; color: #666; font-size: 0.78rem; text-transform: uppercase; letter-spacing: 0.04em; }
  .expense td { padding: 9px 10px; border-bottom: 1px solid #f0f0f0; vertical-align: middle; }
  .expense:last-child td { border-bottom: none; }
  .expense:hover { background: #f7f8fa; }
  .expense .amt { font-weight: 700; color: #1a1a2e; }
  .expense .cat-badge { display: inline-block; padding: 2px 8px; border-radius: 12px; font-size: 0.78rem; font-weight: 600; text-transform: capitalize; }
  .badge-groceries { background: #d1fae5; color: #065f46; }
  .badge-transport { background: #dbeafe; color: #1e40af; }
  .badge-bills { background: #fef3c7; color: #92400e; }
  .badge-fun { background: #ede9fe; color: #5b21b6; }
  .badge-other { background: #f3f4f6; color: #374151; }
  .exp-del { background: none; border: 1px solid #e5e7eb; color: #999; border-radius: 4px; padding: 3px 8px; cursor: pointer; font-size: 0.8rem; }
  .exp-del:hover { background: #fee2e2; border-color: #fca5a5; color: #c0392b; }
  #empty-msg { color: #aaa; font-size: 0.95rem; padding: 20px 0; text-align: center; }
</style>
</head>
<body>
<div class="container">
  <h1>Expense Tracker</h1>

  <div class="card">
    <h2>Add Expense</h2>
    <div class="form-row">
      <div class="form-group">
        <label for="amount">Amount</label>
        <input type="number" id="amount" min="0.01" step="0.01" placeholder="0.00">
      </div>
      <div class="form-group">
        <label for="category">Category</label>
        <select id="category">
          <option value="groceries">Groceries</option>
          <option value="transport">Transport</option>
          <option value="bills">Bills</option>
          <option value="fun">Fun</option>
        </select>
      </div>
      <div class="form-group">
        <label for="date">Date</label>
        <input type="date" id="date">
      </div>
    </div>
    <div class="form-row">
      <div class="form-group" style="flex:1;min-width:200px;">
        <label for="note">Note (optional)</label>
        <input type="text" id="note" placeholder="What was it for?">
      </div>
    </div>
    <div id="form-error"></div>
    <button id="add-expense">Add Expense</button>
  </div>

  <div class="card">
    <h2>Filters</h2>
    <div class="filters">
      <div class="form-group">
        <label for="filter-category">Category</label>
        <select id="filter-category">
          <option value="all">All Categories</option>
          <option value="groceries">Groceries</option>
          <option value="transport">Transport</option>
          <option value="bills">Bills</option>
          <option value="fun">Fun</option>
        </select>
      </div>
      <div class="form-group">
        <label for="filter-from">From</label>
        <input type="date" id="filter-from">
      </div>
      <div class="form-group">
        <label for="filter-to">To</label>
        <input type="date" id="filter-to">
      </div>
    </div>
  </div>

  <div class="card">
    <h2>Summary</h2>
    <div id="total-row">Visible Total: <span id="total">0.00</span></div>
    <div class="summary-grid" id="cat-summary">
      <div class="cat-box">
        <div class="cat-label">Groceries</div>
        <div class="cat-total" data-cat="groceries">0.00</div>
      </div>
      <div class="cat-box">
        <div class="cat-label">Transport</div>
        <div class="cat-total" data-cat="transport">0.00</div>
      </div>
      <div class="cat-box">
        <div class="cat-label">Bills</div>
        <div class="cat-total" data-cat="bills">0.00</div>
      </div>
      <div class="cat-box">
        <div class="cat-label">Fun</div>
        <div class="cat-total" data-cat="fun">0.00</div>
      </div>
    </div>

    <table id="expense-table">
      <thead>
        <tr>
          <th>Date</th>
          <th>Category</th>
          <th>Amount</th>
          <th>Note</th>
          <th></th>
        </tr>
      </thead>
      <tbody id="expense-list"></tbody>
    </table>
    <div id="empty-msg" style="display:none;">No expenses match the current filters.</div>
  </div>
</div>

<script>
  const CATS = ['groceries', 'transport', 'bills', 'fun'];
  let expenses = [];

  function loadExpenses() {
    try {
      expenses = JSON.parse(localStorage.getItem('expenses') || '[]');
    } catch(e) {
      expenses = [];
    }
  }

  function saveExpenses() {
    localStorage.setItem('expenses', JSON.stringify(expenses));
  }

  function badgeClass(cat) {
    return 'badge-' + (CATS.includes(cat) ? cat : 'other');
  }

  function getFilters() {
    return {
      category: document.getElementById('filter-category').value,
      from: document.getElementById('filter-from').value,
      to: document.getElementById('filter-to').value
    };
  }

  function isVisible(expense, filters) {
    if (filters.category !== 'all' && expense.category !== filters.category) return false;
    if (filters.from && expense.date < filters.from) return false;
    if (filters.to && expense.date > filters.to) return false;
    return true;
  }

  function render() {
    const filters = getFilters();
    const list = document.getElementById('expense-list');
    list.innerHTML = '';

    const sorted = [...expenses].sort((a, b) => {
      if (b.date !== a.date) return b.date.localeCompare(a.date);
      return b.id - a.id;
    });

    let visibleCount = 0;
    let total = 0;
    const catTotals = {};
    CATS.forEach(c => catTotals[c] = 0);

    sorted.forEach(exp => {
      const visible = isVisible(exp, filters);
      const tr = document.createElement('tr');
      tr.className = 'expense';
      tr.dataset.id = exp.id;
      if (!visible) tr.style.display = 'none';

      tr.innerHTML = `
        <td>${exp.date}</td>
        <td><span class="cat-badge ${badgeClass(exp.category)}">${exp.category}</span></td>
        <td class="amt">$${parseFloat(exp.amount).toFixed(2)}</td>
        <td>${exp.note ? exp.note : '<span style="color:#ccc">—</span>'}</td>
        <td><button class="exp-del" data-id="${exp.id}">Delete</button></td>
      `;
      list.appendChild(tr);

      if (visible) {
        visibleCount++;
        total += parseFloat(exp.amount);
        if (catTotals.hasOwnProperty(exp.category)) {
          catTotals[exp.category] += parseFloat(exp.amount);
        }
      }
    });

    document.getElementById('total').textContent = total.toFixed(2);

    CATS.forEach(cat => {
      const el = document.querySelector(`.cat-total[data-cat="${cat}"]`);
      if (el) el.textContent = catTotals[cat].toFixed(2);
    });

    const emptyMsg = document.getElementById('empty-msg');
    if (visibleCount === 0 && expenses.length > 0) {
      emptyMsg.style.display = 'block';
      emptyMsg.textContent = 'No expenses match the current filters.';
    } else if (expenses.length === 0) {
      emptyMsg.style.display = 'block';
      emptyMsg.textContent = 'No expenses yet. Add one above!';
    } else {
      emptyMsg.style.display = 'none';
    }
  }

  document.getElementById('add-expense').addEventListener('click', function() {
    const amountInput = document.getElementById('amount');
    const dateInput = document.getElementById('date');
    const categoryInput = document.getElementById('category');
    const noteInput = document.getElementById('note');
    const errorEl = document.getElementById('form-error');

    const rawAmount = amountInput.value.trim();
    const date = dateInput.value;
    const amount = parseFloat(rawAmount);

    if (!rawAmount || isNaN(amount) || amount <= 0) {
      errorEl.textContent = 'Please enter a valid amount greater than zero.';
      return;
    }
    if (!date) {
      errorEl.textContent = 'Please select a date.';
      return;
    }

    errorEl.textContent = '';
    const expense = {
      id: Date.now(),
      amount: amount,
      category: categoryInput.value,
      date: date,
      note: noteInput.value.trim()
    };

    expenses.push(expense);
    saveExpenses();
    amountInput.value = '';
    noteInput.value = '';
    render();
  });

  document.getElementById('expense-list').addEventListener('click', function(e) {
    if (!e.target.classList.contains('exp-del')) return;
    const id = parseInt(e.target.dataset.id, 10);
    expenses = expenses.filter(exp => exp.id !== id);
    saveExpenses();
    render();
  });

  ['filter-category', 'filter-from', 'filter-to'].forEach(id => {
    document.getElementById(id).addEventListener('change', render);
    document.getElementById(id).addEventListener('input', render);
  });

  loadExpenses();
  render();
</script>
</body>
</html>
